import{_ as a}from"./chunks/微笑狼的公开仓库.gGdYP2E_.js";import{_ as t,o as n,c as i,a2 as r}from"./chunks/framework.DnrXFDHb.js";const f=JSON.parse('{"title":"Automatische Tags","description":"","frontmatter":{},"headers":[],"relativePath":"de-DE/Other/auto-tagging.md","filePath":"de-DE/Other/auto-tagging.md","lastUpdated":1781962217000}'),l={name:"de-DE/Other/auto-tagging.md"};function s(d,e,o,g,c,u){return n(),i("div",null,[...e[0]||(e[0]=[r('<h1 id="automatische-tags" tabindex="-1">Automatische Tags <a class="header-anchor" href="#automatische-tags" aria-label="Permalink to &quot;Automatische Tags&quot;">​</a></h1><p>Automatische Tags werden hier konfiguriert:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Systemeinstellungen -&gt; Weitere Einstellungen -&gt; Automatische Tags</span></span></code></pre></div><p>Die Funktion erzeugt Tags für Bilder und erleichtert Suche, Filter der Zufallsbild-API, öffentliche Galerie und Zugriffskontrolle nach Altersfreigabe.</p><h2 id="funktionen" tabindex="-1">Funktionen <a class="header-anchor" href="#funktionen" aria-label="Permalink to &quot;Funktionen&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Funktion</th><th>Beschreibung</th></tr></thead><tbody><tr><td>Inhaltstags</td><td>Tags für Personen, Szenen, Objekte, Stil und weitere visuelle Merkmale</td></tr><tr><td>Charakter-Tags</td><td>Nützlich für Anime-Bilder und Illustrationen</td></tr><tr><td>Ausrichtungstags</td><td>Ergänzt <code>landscape</code>, <code>portrait</code> oder <code>square</code></td></tr><tr><td>Bildeinstufung</td><td>Speichert Ergebnisse <code>G/S/Q/E</code></td></tr><tr><td>Tagging beim Upload</td><td>Verarbeitet neue Bilder automatisch</td></tr><tr><td>Stapel-Tagging</td><td>Ergänzt Tags für ältere Bilder in einem oder mehreren Ordnern</td></tr></tbody></table><h2 id="vorbereitung" tabindex="-1">Vorbereitung <a class="header-anchor" href="#vorbereitung" aria-label="Permalink to &quot;Vorbereitung&quot;">​</a></h2><p>Du brauchst mindestens eine erreichbare Hugging Face Space-URL.</p><p>Empfohlen ist, den Space <code>wd-tagger</code> von SmilingWolf in dein eigenes Hugging Face-Konto zu duplizieren:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://huggingface.co/spaces/SmilingWolf/wd-tagger</span></span></code></pre></div><p>Der öffentliche Space eignet sich zum Testen, wird aber von vielen Personen geteilt und kann langsam, ausgelastet oder zeitweise nicht verfügbar sein. Für dauerhafte Nutzung ist eine eigene Kopie stabiler.</p><h2 id="space-duplizieren" tabindex="-1">Space duplizieren <a class="header-anchor" href="#space-duplizieren" aria-label="Permalink to &quot;Space duplizieren&quot;">​</a></h2><ol><li>Melde dich bei Hugging Face an.</li><li>Öffne <code>https://huggingface.co/spaces/SmilingWolf/wd-tagger</code>.</li></ol><p><img src="'+a+`" alt="Öffentlicher SmilingWolf-Space" loading="lazy"></p><ol start="3"><li>Öffne das Menü oben rechts.</li><li>Wähle <code>Duplicate this Space</code>.</li><li>Behalte den Namen oder nutze einen klaren Namen wie <code>wd-tagger</code>.</li><li>Lass den Space auf <code>Public</code>, damit ImgBed ihn einfacher aufrufen kann.</li><li>Starte mit kostenloser Hardware.</li><li>Erstelle den Space und warte, bis der Build abgeschlossen ist.</li></ol><p>Kopiere danach die Browser-URL und füge sie in ImgBed unter <code>Space URLs</code> ein.</p><h2 id="empfohlene-einstellungen" tabindex="-1">Empfohlene Einstellungen <a class="header-anchor" href="#empfohlene-einstellungen" aria-label="Permalink to &quot;Empfohlene Einstellungen&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Option</th><th>Empfehlung</th></tr></thead><tbody><tr><td><code>Space URLs</code></td><td>Eine URL pro Zeile</td></tr><tr><td>Zielordner</td><td>Leer für alle Dateien; Ordner wählen, wenn du begrenzen möchtest</td></tr><tr><td>Modell</td><td>Zuerst <code>wd-swinv2-tagger-v3</code> verwenden</td></tr><tr><td>Schwelle für allgemeine Tags</td><td>Etwa bei <code>0.35</code> beginnen</td></tr><tr><td>Schwelle für Charakter-Tags</td><td>Etwa <code>0.85</code>, um Fehlzuordnungen zu reduzieren</td></tr><tr><td><code>MCut</code></td><td>Anfangs deaktiviert lassen</td></tr><tr><td>Tagging beim Upload</td><td>Aktivieren, wenn neue Bilder automatisch verarbeitet werden sollen</td></tr></tbody></table><p>Bei zu vielen Tags erhöhe die allgemeine Schwelle leicht. Bei zu wenigen Tags senke sie etwas.</p><h2 id="stapel-tagging" tabindex="-1">Stapel-Tagging <a class="header-anchor" href="#stapel-tagging" aria-label="Permalink to &quot;Stapel-Tagging&quot;">​</a></h2><ol><li>Trage <code>Space URLs</code> ein.</li><li>Wähle einen Zielordner.</li><li>Starte das Tagging.</li><li>Warte, bis der Fortschritt abgeschlossen ist.</li></ol><p>Ist der Zielordner leer, verarbeitet ImgBed alle Ordner.</p><h2 id="tagging-beim-upload" tabindex="-1">Tagging beim Upload <a class="header-anchor" href="#tagging-beim-upload" aria-label="Permalink to &quot;Tagging beim Upload&quot;">​</a></h2><p>Wenn aktiv, rufen neue Bilder automatisch die konfigurierten <code>Space URLs</code> auf.</p><p>Ist der Space ausgelastet, kann der Upload zuerst fertig werden; das Tagging läuft anschließend im Hintergrund weiter.</p><h2 id="haufige-fragen" tabindex="-1">Häufige Fragen <a class="header-anchor" href="#haufige-fragen" aria-label="Permalink to &quot;Häufige Fragen&quot;">​</a></h2><h3 id="warum-einen-eigenen-space-duplizieren" tabindex="-1">Warum einen eigenen Space duplizieren? <a class="header-anchor" href="#warum-einen-eigenen-space-duplizieren" aria-label="Permalink to &quot;Warum einen eigenen Space duplizieren?&quot;">​</a></h3><p>Öffentliche Spaces werden von vielen genutzt. Eine eigene Kopie ist für deine Seite meist schneller und stabiler.</p><h3 id="warum-sind-tags-auf-englisch" tabindex="-1">Warum sind Tags auf Englisch? <a class="header-anchor" href="#warum-sind-tags-auf-englisch" aria-label="Permalink to &quot;Warum sind Tags auf Englisch?&quot;">​</a></h3><p>Das ist normal. SmilingWolf-Modelle liefern englische Tags. ImgBed nutzt sie für Suche, Filter, Zufallsbild-API und öffentliche Galerie.</p><h3 id="wofur-ist-die-einstufung" tabindex="-1">Wofür ist die Einstufung? <a class="header-anchor" href="#wofur-ist-die-einstufung" aria-label="Permalink to &quot;Wofür ist die Einstufung?&quot;">​</a></h3><p>Die Einstufung arbeitet mit dem Sicherheits-Zugriffsmodus zusammen. Wenn Besucher nach Altersfreigabe eingeschränkt werden, folgen Galerie und Zufallsbild-API diesen Regeln.</p><h2 id="schnellablauf" tabindex="-1">Schnellablauf <a class="header-anchor" href="#schnellablauf" aria-label="Permalink to &quot;Schnellablauf&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Bei Hugging Face anmelden</span></span>
<span class="line"><span>-&gt; SmilingWolf/wd-tagger öffnen</span></span>
<span class="line"><span>-&gt; Space duplizieren</span></span>
<span class="line"><span>-&gt; Build abwarten</span></span>
<span class="line"><span>-&gt; Space-URL kopieren</span></span>
<span class="line"><span>-&gt; In Space URLs eintragen</span></span>
<span class="line"><span>-&gt; Modell und Schwellen setzen</span></span>
<span class="line"><span>-&gt; Tagging starten oder Tagging beim Upload aktivieren</span></span></code></pre></div>`,34)])])}const m=t(l,[["render",s]]);export{f as __pageData,m as default};
